// Groq returns OpenAI format: response.choices[0].message.content
const response = $input.first().json;
const content = response.choices?.[0]?.message?.content || '';

if (!content) {
  return [{ json: { keywords: [], error: 'No response from Groq' } }];
}

// Extract JSON array from response
const jsonMatch = content.match(/\[[\s\S]*?\]/);
let keywords = [];

if (jsonMatch) {
  try {
    keywords = JSON.parse(jsonMatch[0]);
  } catch(e) {
    // Fallback: split by comma
    keywords = content.replace(/[\[\]"]/g, '').split(',').map(k => k.trim());
  }
}

return [{ json: { keywords: keywords.slice(0, 6) } }];

// Input: 2 items from Merge (Append)
const keywords = $input.all().find(i => i.json.keywords)?.json.keywords || [];
const templates = $input.all().find(i => i.json.templates)?.json.templates || [];

return [{
  json: {
    keywords,
    templates
  }
}];

const memes = $input.first().json.data?.memes || [];
const keywords = ($input.first().json.keywords || []).slice(0, 3).map(k => k.toLowerCase());
const trendingNames = ($input.first().json.trending_template_names || []).map(n => n.toLowerCase());

// 1. Calculate the scores (Keep your original logic)
const scored = memes.map(meme => {
  const name = meme.name.toLowerCase();
  const keywordScore = keywords.filter(k => name.includes(k)).length;
  const trendScore = trendingNames.some(t => {
    const tWords = t.split(' ');
    return tWords.some(w => w.length > 4 && name.includes(w));
  }) ? 1 : 0;
  return { ...meme, score: keywordScore + trendScore };
});

// 2. The Fix: Keep top 15, mix in 15 random others for variety
const top15 = scored.sort((a, b) => b.score - a.score).slice(0, 15);
const theRest = scored.slice(15).sort(() => 0.5 - Math.random()).slice(0, 15);

// 3. Combine and shuffle the 30 templates so Groq gets high relevance AND high variety
const combinedPool = [...top15, ...theRest].sort(() => 0.5 - Math.random());

return [{
  json: {
    templates: combinedPool,
    keywords: keywords
  }
}];

const response = $input.first().json;
const content = response.choices?.[0]?.message?.content || '';
const allMemes = $('Get_100_templets1').first().json.data?.memes || [];

const jsonMatch = content.match(/\[[\s\S]*?\]/);

if (!jsonMatch) {
