}

return [{ json: { selected_templates: selected } }];

const input = $('Code in JavaScript5').first().json;

// Get keywords - try multiple sources
const keywords = $('Filter_templet1').first().json.keywords ||
                 $('Code in JavaScript6').first().json.keywords || [];

// Get templates from Filter_templet1
const templates = $json.templates || $('Filter_templet1').first().json.templates || [];

// Get trending Reddit template names for context
const trendingNames = $('Merge_Templates').first().json.trending_template_names || [];

const templatesText = templates
  .map(t => `- "${t.name}" (ID: ${t.id})`)
