const trendingText = trendingNames.length > 0
  ? `\nCURRENTLY TRENDING TEMPLATE STYLES (use as inspiration):\n${trendingNames.join(', ')}`
  : '';

return {
  json: {
    model: "meta-llama/llama-4-scout-17b-16e-instruct",
