const raw = $input.first().json;
const originalMemes = $('Enrich_Meme_Output').first().json.memes || [];

let aiResults = [];
try {
  const content = raw.choices?.[0]?.message?.content || '[]';
  const cleaned = content.replace(/```json|```/g, '').trim();
  aiResults = JSON.parse(cleaned);
  if (!Array.isArray(aiResults)) {
    aiResults = [aiResults];
  }
} catch (e) {
  console.log("Parse error:", e.message);
}

return originalMemes.map((memeData, index) => {
  let jarvis = {};
  try {
    const parsed = aiResults[index] || aiResults[0] || {};
    const p = parsed.parameters || {
        social_currency: 0, triggers: 0, emotion: 0, public_value: 0, practical_value: 0, storytelling: 0,
        visual_familiarity: 0, text_density: 0, sentiment_polarity: 0, subject_prominence: 0,
        visual_hooks: 0, share_friction: 0, relatability_breadth: 0
    };

    const stepps    = (p.social_currency + p.triggers + p.emotion + p.public_value + p.practical_value + p.storytelling) / 6 || 0;
    const cognitive = (p.visual_familiarity + p.text_density + p.sentiment_polarity + p.subject_prominence) / 4 || 0;
    const tipping   = (p.visual_hooks + p.share_friction + p.relatability_breadth) / 3 || 0;
    const virality  = (stepps * 0.50) + (cognitive * 0.25) + (tipping * 0.25) || 0;

    jarvis = {
      parameters: p,
      scores: {
        stepps_score:    Math.round(stepps * 100) / 100,
        cognitive_score: Math.round(cognitive * 100) / 100,
        tipping_score:   Math.round(tipping * 100) / 100,
        virality_score:  Math.round(virality * 100) / 100
      },
      verdict:   virality >= 3.5 ? "VIRAL" : "NOT_VIRAL",
      reasoning: parsed.reasoning || "Failed to evaluate."
    };
  } catch(e) {
    jarvis = { scores: {virality_score: 0, stepps_score: 0, cognitive_score: 0, tipping_score: 0}, verdict: "NOT_VIRAL", parameters: {}, reasoning: "Error" };
  }

  const scores = jarvis.scores;
  return {
    json: {
      status:          scores.virality_score >= 3.5 ? "Approved ✅" : "Low Virality ❌",
      meme_url:        memeData.url           || "",
      page_url:        memeData.page_url      || "",
      template_name:   memeData.template_name || "",
      caption_top:     memeData.text0         || "",
      caption_bottom:  memeData.text1         || "",
      virality_score:  scores.virality_score,
      stepps_score:    scores.stepps_score,
      cognitive_score: scores.cognitive_score,
      tipping_score:   scores.tipping_score,
      verdict:         jarvis.verdict,
      reasoning:       jarvis.reasoning,
      parameters:      jarvis.parameters
    }
  };
});

return $input.all().map(item => {
  return {
    json: {
      url:           item.json.url,
      page_url:      item.json.page_url,
