const items = $input.all();
const templateItems = $('Store_Template_ID').all();
const allMemes = $('Get_100_templets1').first().json.data?.memes || [];
const output = [];

const enforceWordLimit = (text, limit) => {
  if (!text) return "";
  return text.trim().replace(/\n/g, " ").split(/\s+/).slice(0, limit).join(" ");
};

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const content = item.json.choices?.[0]?.message?.content || '';

  const templateId   = String(templateItems[i]?.json?.id || '');
  const templateName = String(templateItems[i]?.json?.name || '');
  const foundMeme = allMemes.find(m => String(m.id) === templateId);
  const boxCount = foundMeme ? foundMeme.box_count : 2; 

  if (!content) continue;

  const jsonMatch = content.match(/\{[\s\S]*?\}/);
  if (!jsonMatch) continue;

  let parsed;
  try {
    parsed = JSON.parse(jsonMatch[0]);
  } catch(err) {
    continue;
  }

  // 🔒 SECURED: No credentials here at all!
  const imgflipPayload = {
    template_id: templateId
  };

  if (parsed.text0 && boxCount > 0) imgflipPayload["boxes[0][text]"] = enforceWordLimit(parsed.text0, 10);
  if (parsed.text1 && boxCount > 1) imgflipPayload["boxes[1][text]"] = enforceWordLimit(parsed.text1, 10);
  if (parsed.text2 && boxCount > 2) imgflipPayload["boxes[2][text]"] = enforceWordLimit(parsed.text2, 10);
  if (parsed.text3 && boxCount > 3) imgflipPayload["boxes[3][text]"] = enforceWordLimit(parsed.text3, 10);

  output.push({
    json: {
      id: templateId,
      name: templateName,
      imgflip_payload: imgflipPayload,
      template_name: templateName,           // ADD THIS
      text0: enforceWordLimit(parsed.text0, 10),  // ADD THIS
      text1: enforceWordLimit(parsed.text1, 10)   // ADD THIS
    }
  });
}

return output;

return $input.all().map((item, i) => {
  const output = {
    json: {
      // Meme data
      url:           item.json.url,
      page_url:      item.json.page_url,
      text0:         item.json.text0,
      text1:         item.json.text1,
      template_name: item.json.template_name || "",
      meme_url:      item.json.url,
      _idx:          i,

      // Virality scores (CRITICAL!)
      status:        item.json.status || "Low Virality ❌",
      virality_score: item.json.virality_score ?? 0,
      stepps_score:  item.json.stepps_score ?? 0,
      cognitive_score: item.json.cognitive_score ?? 0,
      tipping_score: item.json.tipping_score ?? 0,
      verdict:       item.json.verdict || "NOT_VIRAL",
      reasoning:     item.json.reasoning || "",

      // Scoring parameters
      parameters:    item.json.parameters || {
        social_currency: 0,
        triggers: 0,
        emotion: 0,
        public_value: 0,
        practical_value: 0,
        storytelling: 0,
        visual_familiarity: 0,
        text_density: 0,
        sentiment_polarity: 0,
        subject_prominence: 0,
        visual_hooks: 0,
        share_friction: 0,
        relatability_breadth: 0
      }
    }
  };

  if (item.binary && item.binary.data) {
    output.binary = { data: item.binary.data };
  }

  return output;
});
